def normalize_ui_language(raw: str | None) -> str:
    key = str(raw or "").strip()
    if key in UI_LANGUAGE_LABELS:
        return key
    low = key.lower()
    aliases = {
        "zh": "zh-CN",
        "zh-cn": "zh-CN",
        "zh_simplified": "zh-CN",
        "cn": "zh-CN",
        "zh-tw": "zh-TW",
        "zh-hk": "zh-TW",
        "zh_hant": "zh-TW",
        "tc": "zh-TW",
        "ja-jp": "ja",
        "jp": "ja",
        "en-us": "en",
        "en-gb": "en",
    }
    mapped = aliases.get(low)
    if mapped and mapped in UI_LANGUAGE_LABELS:
        return mapped
    return DEFAULT_UI_LANGUAGE


def supported_ui_languages_payload() -> list[dict]:
    return [dict(x) for x in SUPPORTED_UI_LANGUAGES]


def normalize_execution_mode(raw: str | None, default: str = EXECUTION_MODE_SYNC) -> str:
    key = str(raw or "").strip().lower().replace("-", "_")
    aliases = {
        "single": EXECUTION_MODE_SINGLE,
        "legacy": EXECUTION_MODE_SINGLE,
        "sequential": EXECUTION_MODE_SEQUENTIAL,
        "async_sequential": EXECUTION_MODE_SEQUENTIAL,
        "pipeline": EXECUTION_MODE_SEQUENTIAL,
        "sync": EXECUTION_MODE_SYNC,
        "synchronous": EXECUTION_MODE_SYNC,
        "collaborative": EXECUTION_MODE_SYNC,
        "sync_collab": EXECUTION_MODE_SYNC,
    }
    mapped = aliases.get(key, "")
    if mapped in EXECUTION_MODE_CHOICES:
        return mapped
    fallback = str(default or EXECUTION_MODE_SYNC).strip().lower()
    if fallback in EXECUTION_MODE_CHOICES:
        return fallback
    return EXECUTION_MODE_SYNC


def model_language_instruction(lang: str) -> str:
    code = normalize_ui_language(lang)
    if code == "zh-CN":
        return (
            "Language policy: use Simplified Chinese by default for all user-facing answers, plans, "
            "blackboard notes, manager delegates, and agent-bus collaboration messages. "
            "Only switch language when user explicitly requests it. "
            "Do not translate code, file paths, commands, API/tool names, or JSON keys."
        )
    if code == "zh-TW":
        return (
            "Language policy: use Traditional Chinese by default for all user-facing answers, plans, "
            "blackboard notes, manager delegates, and agent-bus collaboration messages. "
            "Only switch language when user explicitly requests it. "
            "Do not translate code, file paths, commands, API/tool names, or JSON keys."
        )
    if code == "ja":
        return (
            "Language policy: use Japanese by default for all user-facing answers, plans, "
            "blackboard notes, manager delegates, and agent-bus collaboration messages. "
            "Only switch language when user explicitly requests it. "
            "Do not translate code, file paths, commands, API/tool names, or JSON keys."
        )
    return (
        "Language policy: use English by default for all user-facing answers, plans, "
        "blackboard notes, manager delegates, and agent-bus collaboration messages. "
        "Only switch language when user explicitly requests it. "
        "Do not translate code, file paths, commands, API/tool names, or JSON keys."
    )


def _detect_os_shell_instruction() -> str:
    """Return a shell environment note for the agent system prompt based on the host OS."""
    import platform as _platform
    _sys = _platform.system()
    if _sys == "Windows":
        return (
            "Shell environment: Windows (cmd.exe via shell=True). "
            "IMPORTANT — use Windows-native commands only: "
            "use 'dir' (not 'ls'), 'type' (not 'cat'), 'del' (not 'rm'), "
            "'move' (not 'mv'), 'copy' (not 'cp'), 'findstr' (not 'grep'), "
            "'where' (not 'which'), 'echo %VAR%' (not 'echo $VAR'). "
            "To list files recursively use 'dir /s /b'. "
            "Path separator is backslash (\\). "
            "Do NOT use POSIX paths like /workspace, /tmp, /usr, ~/... — they do not exist. "
            "Working directory is already set; use relative paths or the absolute session root shown above."
        )
    if _sys == "Darwin":
        return (
            "Shell environment: macOS (bash/zsh). "
            "Standard POSIX commands are available (ls, cat, grep, find, etc.). "
            "Package manager is 'brew'. "
            "Do NOT assume Linux-specific paths like /proc or /etc/os-release exist. "
            "Use relative paths or the absolute session root shown above."
        )
    # Linux / other POSIX
    return (
        "Shell environment: Linux (bash). "
        "Standard POSIX commands are available (ls, cat, grep, find, etc.). "
        "Use relative paths or the absolute session root shown above."
    )

def resolve_web_ui_dir_path(raw: str, base_dir: Path | None = None) -> Path:
    txt = str(raw or "").strip()
    if not txt:
        txt = DEFAULT_WEB_UI_DIR
    p = Path(txt).expanduser()
    if p.is_absolute():
        return p.resolve()
    return ((base_dir or WORKDIR).resolve() / p).resolve()


def resolve_optional_file_path(raw: str, base_dir: Path | None = None) -> Path:
    txt = str(raw or "").strip()
    if not txt:
        return ((base_dir or WORKDIR).resolve() / DEFAULT_WEB_UI_CONFIG).resolve()
    p = Path(txt).expanduser()
    if p.is_absolute():
        return p.resolve()
    return ((base_dir or WORKDIR).resolve() / p).resolve()


def load_web_ui_config_file(path: Path) -> dict:
    if not path.exists() or not path.is_file():
        return {}
    try:
        raw = path.read_text(encoding="utf-8")
    except Exception:
        try:
            raw = path.read_text(encoding="utf-8-sig")
        except Exception:
            return {}
    try:
        parsed = json.loads(raw)
    except Exception:
        return {}
    return parsed if isinstance(parsed, dict) else {}


def extract_show_upload_list_setting(raw: object) -> bool | None:
    if not isinstance(raw, dict):
        return None
    keys = ("show_upload_list", "upload_list_visible", "enable_upload_list")
    for key in keys:
        if key in raw:
            return _to_bool_like(raw.get(key), default=False)
    for section_key in ("web_ui", "ui", "frontend"):
        section = raw.get(section_key)
        if not isinstance(section, dict):
            continue
        for key in keys:
            if key in section:
                return _to_bool_like(section.get(key), default=False)
    return None


def default_multimodal_capabilities() -> dict[str, bool]:
    return {
        "input_image": False,
        "input_audio": False,
        "input_video": False,
        "output_image": False,
        "output_audio": False,
        "output_video": False,
    }


def _to_bool_like(raw: object, default: bool = False) -> bool:
    if isinstance(raw, bool):
        return raw
    if isinstance(raw, (int, float)):
        return bool(raw)
    txt = str(raw or "").strip().lower()
    if txt in {"1", "true", "yes", "y", "on", "enabled", "enable"}:
        return True
    if txt in {"0", "false", "no", "n", "off", "disabled", "disable"}:
        return False
    return default


def infer_model_multimodal_capabilities(provider: str, model: str) -> dict[str, bool]:
    caps = default_multimodal_capabilities()
    p = str(provider or "").strip().lower()
    m = str(model or "").strip().lower()
    if p == "ollama":
        if any(x in m for x in ("vision", "-vl", "llava", "minicpm-v", "internvl", "qwen2.5-vl", "qwen-vl", "gemma3")):
            caps["input_image"] = True
        if any(x in m for x in ("omni", "audio", "speech", "voice")):
            caps["input_audio"] = True
        if any(x in m for x in ("omni", "video")):
            caps["input_video"] = True
        return caps
    if p in {"openai_compat", "openai", "siliconflow", "custom_http"}:
        if any(
            x in m
            for x in (
                "gpt-4o",
                "gpt-4.1",
                "vision",
                "-vl",
                "qwen-vl",
                "gemini",
                "claude-3",
                "omni",
            )
        ):
            caps["input_image"] = True
        if any(x in m for x in ("omni", "audio", "speech", "voice", "realtime")):
            caps["input_audio"] = True
        if any(x in m for x in ("video", "omni")):
            caps["input_video"] = True
        if any(x in m for x in ("gpt-image", "dall-e", "sdxl", "stable-diffusion", "flux", "kolors")):
            caps["output_image"] = True
        if any(x in m for x in ("tts", "audio", "speech", "voice")):
            caps["output_audio"] = True
        if any(x in m for x in ("video", "sora", "kling", "wan")):
            caps["output_video"] = True
    return caps


def parse_capability_overrides(raw: object) -> dict[str, bool]:
    obj = raw
    if isinstance(raw, str):
        txt = raw.strip()
        if not txt:
            return {}
        obj = parse_json_object(txt, {})
    if not isinstance(obj, dict):
        return {}
    out: dict[str, bool] = {}
    aliases = {
        "image_input": "input_image",
        "input_images": "input_image",
        "image_in": "input_image",
        "audio_input": "input_audio",
        "input_audios": "input_audio",
        "audio_in": "input_audio",
        "video_input": "input_video",
        "input_videos": "input_video",
        "video_in": "input_video",
        "image_output": "output_image",
        "output_images": "output_image",
        "image_out": "output_image",
        "audio_output": "output_audio",
        "output_audios": "output_audio",
        "audio_out": "output_audio",
        "video_output": "output_video",
        "output_videos": "output_video",
        "video_out": "output_video",
    }
    for key, value in obj.items():
        k = str(key or "").strip().lower()
        if not k:
            continue
        mapped = aliases.get(k, k)
        if mapped in MEDIA_CAPABILITY_KEYS:
            out[mapped] = _to_bool_like(value, default=False)
    return out


def merge_multimodal_capabilities(base: dict[str, bool], override: dict[str, bool]) -> dict[str, bool]:
    out = default_multimodal_capabilities()
    for key in MEDIA_CAPABILITY_KEYS:
        out[key] = bool(base.get(key, False))
    for key, value in override.items():
        if key in MEDIA_CAPABILITY_KEYS:
            out[key] = bool(value)
    return out


def parse_media_endpoints(raw: object) -> dict[str, str]:
    obj = raw
    if isinstance(raw, str):
        txt = raw.strip()
        if not txt:
            return {}
        obj = parse_json_object(txt, {})
    if not isinstance(obj, dict):
        return {}
    out: dict[str, str] = {}
    for media_type in ("image", "audio", "video"):
        v = str(obj.get(media_type, "") or "").strip()
        if v:
            out[media_type] = v
    return out


def guess_mime_from_name(name: str, fallback: str = "application/octet-stream") -> str:
    mime, _ = mimetypes.guess_type(str(name or ""))
    return str(mime or fallback)


def guess_ext_from_mime(mime: str, fallback: str = ".bin") -> str:
    ext = mimetypes.guess_extension(str(mime or "").split(";", 1)[0].strip().lower())
    if not ext:
        return fallback
    if ext == ".jpe":
        return ".jpg"
    return ext

def now_ts() -> float:
    return time.time()


_benign_socket_log_lock = threading.Lock()
_benign_socket_log_state: dict[str, dict[str, float | int]] = {}


def filter_runtime_noise_lines(text: str) -> tuple[str, int]:
    raw = str(text or "")
    if not raw:
        return "", 0
    kept: list[str] = []
    dropped = 0
    for line in raw.splitlines():
        row = str(line or "")
        if any(p.search(row) for p in SOCKET_NOISE_LINE_PATTERNS):
            dropped += 1
            continue
        kept.append(row)
    return "\n".join(kept).strip(), int(dropped)


def is_benign_socket_error(exc: BaseException | None) -> bool:
    if exc is None:
        return False
    if isinstance(exc, (BrokenPipeError, ConnectionResetError, ConnectionAbortedError, TimeoutError)):
        return True
    if not isinstance(exc, OSError):
        return False
    winerror = int(getattr(exc, "winerror", 0) or 0)
    if winerror in {10038, 10053, 10054, 10057, 10093}:  # 10093 = WSANOTINITIALISED (selector on pipe)
        return True
    err = int(getattr(exc, "errno", 0) or 0)
    benign_errno = {
        int(getattr(errno, "EPIPE", 32)),
        int(getattr(errno, "ECONNRESET", 104)),
        int(getattr(errno, "ECONNABORTED", 103)),
        int(getattr(errno, "ENOTCONN", 107)),
        int(getattr(errno, "EBADF", 9)),
    }
    return err in benign_errno


def _socket_error_code(exc: BaseException | None) -> str:
    if not isinstance(exc, OSError):
        return str(type(exc).__name__ if exc is not None else "unknown")
    winerror = int(getattr(exc, "winerror", 0) or 0)
    if winerror > 0:
        return f"winerror:{winerror}"
    err = int(getattr(exc, "errno", 0) or 0)
    if err > 0:
        return f"errno:{err}"
    return str(type(exc).__name__ if exc is not None else "OSError")


def _log_benign_socket_error_limited(exc: BaseException | None, where: str = ""):
    if not BENIGN_SOCKET_DEBUG_LOG_ENABLED:
        return
    code = _socket_error_code(exc)
    location = str(where or "runtime").strip()
    key = f"{location}|{code}"
    now = now_ts()
    suppressed = 0
    should_emit = False
    with _benign_socket_log_lock:
        row = _benign_socket_log_state.get(key)
        if not isinstance(row, dict):
            _benign_socket_log_state[key] = {"last_ts": now, "suppressed": 0}
            should_emit = True
        else:
            last_ts = float(row.get("last_ts", 0.0) or 0.0)
            if now - last_ts >= BENIGN_SOCKET_LOG_INTERVAL_SECONDS:
                suppressed = int(row.get("suppressed", 0) or 0)
                row["last_ts"] = now
                row["suppressed"] = 0
                should_emit = True
            else:
                row["suppressed"] = int(row.get("suppressed", 0) or 0) + 1
        if len(_benign_socket_log_state) > 512:
            stale = sorted(
                _benign_socket_log_state.items(),
                key=lambda item: float((item[1] or {}).get("last_ts", 0.0) if isinstance(item[1], dict) else 0.0),
            )[:128]
            for dead_key, _ in stale:
                _benign_socket_log_state.pop(dead_key, None)
    if should_emit:
        msg = f"[web-agent][debug] benign socket error {code} at {location}"
        if suppressed > 0:
            msg = f"{msg} (+{suppressed} suppressed)"
        print(msg, file=sys.stderr)


def swallow_benign_socket_error(exc: BaseException | None, where: str = "") -> bool:
    if not is_benign_socket_error(exc):
        return False
    _log_benign_socket_error_limited(exc, where)
    return True


def normalize_timeout_seconds(
    raw: object,
    *,
    minimum: int = MIN_TIMEOUT_SECONDS,
    maximum: int = MAX_TIMEOUT_SECONDS,
    fallback: int = DEFAULT_TIMEOUT_SECONDS,
) -> int:
    try:
        value = int(float(raw))
    except Exception:
        value = int(fallback)
    if maximum > 0:
        value = min(value, int(maximum))
    return max(int(minimum), int(value))

def detect_local_lan_ip() -> str:
    try:
        s = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        s.connect(("8.8.8.8", 80))
        ip = str(s.getsockname()[0] or "").strip()
        s.close()
        if ip and ip != "127.0.0.1":
            return ip
    except Exception:
        pass
    return "127.0.0.1"

def json_dumps(obj: object, *, indent: int | None = None) -> str:
    return json.dumps(obj, ensure_ascii=False, indent=indent)

def make_id(prefix: str) -> str:
    return f"{prefix}_{uuid.uuid4().hex[:8]}"

def sanitize_profile_id(raw: str) -> str:
    pid = re.sub(r"[^A-Za-z0-9._-]+", "-", (raw or "").strip().lower()).strip("-")
    return pid or "profile"

def detect_repo_root(cwd: Path) -> Path | None:
    try:
        r = subprocess.run(
            ["git", "rev-parse", "--show-toplevel"],
            cwd=cwd,
            capture_output=True,
            text=True,
            timeout=10,
        )
        if r.returncode != 0:
            return None
        root = Path(r.stdout.strip())
        return root if root.exists() else None
    except Exception:
        return None

REPO_ROOT = detect_repo_root(WORKDIR) or WORKDIR

def safe_path(path_text: str, base: Path | None = None) -> Path:
    root = (base or WORKDIR).resolve()
    raw = str(path_text or "").strip()
    if not raw:
        raise ValueError("path required")
    candidate = Path(raw)
    path = candidate.resolve() if candidate.is_absolute() else (root / raw).resolve()
    if not path.is_relative_to(root):
        raise ValueError(f"path escapes workspace: {path_text}")
    return path

def _safe_js_filename(name: str, fallback: str = "lib.js") -> str:
    raw = Path(str(name or fallback)).name
    safe = re.sub(r"[^A-Za-z0-9._-]+", "_", raw).strip("._")
    if not safe:
        safe = fallback
    if not safe.lower().endswith(".js"):
        safe = f"{safe}.js"
    return safe

def _sha256_bytes(raw: bytes) -> str:
    return hashlib.sha256(raw).hexdigest()

def _sha256_file(fp: Path) -> str:
    h = hashlib.sha256()
    with fp.open("rb") as f:
        while True:
            block = f.read(65536)
            if not block:
                break
            h.update(block)
    return h.hexdigest()

def _download_http_bytes(url: str, timeout: float = 25.0) -> tuple[bytes, str]:
    req = Request(
        str(url or "").strip(),
        headers={"User-Agent": "Mozilla/5.0 (StandaloneWebSessionAgent)"},
        method="GET",
    )
    with urlopen(req, timeout=timeout) as resp:
        ctype = str(resp.headers.get("Content-Type", "") or "").strip()
        return resp.read(), ctype

def offline_js_lib_root(workdir: Path = WORKDIR) -> Path:
    return (workdir / "js_lib").resolve()

def _render_offline_js_catalog_md() -> str:
    rows = [
        "# Offline JS Library Catalog",
        "",
        "Pre-fetched common JS libraries for offline HTML deliverables.",
        "",
        "| id | filename | source urls |",
        "|---|---|---|",
    ]
    for row in OFFLINE_JS_LIB_CATALOG:
        lib_id = str(row.get("id", "") or "").strip()
        filename = str(row.get("filename", "") or "").strip()
        urls = [str(x).strip() for x in (row.get("urls") or []) if str(x).strip()]
        rows.append(f"| `{lib_id}` | `{filename}` | {'<br>'.join(urls)} |")
    return "\n".join(rows) + "\n"

def load_offline_js_lib_index(js_root: Path) -> dict:
    fp = (js_root / OFFLINE_JS_LIB_INDEX_FILE).resolve()
    if not fp.exists():
        return {}
    try:
        raw = fp.read_text(encoding="utf-8")
        obj = json.loads(raw)
        return obj if isinstance(obj, dict) else {}
    except Exception:
        return {}

def ensure_offline_js_libs(workdir: Path = WORKDIR, force: bool = False) -> dict:
    root = offline_js_lib_root(workdir)
    root.mkdir(parents=True, exist_ok=True)
    fetched = 0
    available = 0
    missing = 0
    rows: list[dict] = []
    for entry in OFFLINE_JS_LIB_CATALOG:
        lib_id = str(entry.get("id", "") or "").strip() or "lib"
        filename = _safe_js_filename(str(entry.get("filename", "") or f"{lib_id}.js"), f"{lib_id}.js")
        urls = [str(x).strip() for x in (entry.get("urls") or []) if str(x).strip()]
        match_tokens = [str(x).strip().lower() for x in (entry.get("match_tokens") or []) if str(x).strip()]
        target = root / filename
        source = "existing"
        error = ""
        ok = bool(target.exists() and target.is_file() and target.stat().st_size > 40 and (not force))
        if not ok:
            for url in urls:
                try:
                    data, _ = _download_http_bytes(url, timeout=35.0)
                    if len(data) < 40:
                        error = f"download too small from {url}"
                        continue
                    probe = data[:1024].decode("utf-8", errors="ignore").lower()
                    if "<html" in probe and "<script" not in probe and "tailwind" not in probe:
                        error = f"unexpected html payload from {url}"
                        continue
                    target.write_bytes(data)
                    ok = True
                    source = url
                    fetched += 1
                    break
                except Exception as exc:
                    error = trim(str(exc), 220)
            if not ok:
                source = "missing"
        if ok:
            available += 1
        else:
            missing += 1
        rows.append(
            {
                "id": lib_id,
                "filename": filename,
                "available": ok,
                "size": int(target.stat().st_size) if target.exists() else 0,
                "sha256": _sha256_file(target) if target.exists() else "",
                "source": source,
                "error": error,
                "match_tokens": match_tokens,
                "urls": urls,
            }
        )
    payload = {
        "generated_at": int(now_ts()),
        "js_lib_root": str(root),
        "total": len(OFFLINE_JS_LIB_CATALOG),
        "available": available,
        "missing": missing,
        "fetched": fetched,
        "libs": rows,
    }
    (root / OFFLINE_JS_LIB_INDEX_FILE).write_text(json_dumps(payload, indent=2), encoding="utf-8")
    (root / OFFLINE_JS_LIB_README_FILE).write_text(_render_offline_js_catalog_md(), encoding="utf-8")
    return payload

def _normalize_external_js_url(url: str) -> str:
    raw = html.unescape(str(url or "").strip())
    if raw.startswith("//"):
        raw = f"https:{raw}"
    return raw

def is_external_js_src(url: str) -> bool:
    low = str(url or "").strip().lower()
    return low.startswith("http://") or low.startswith("https://") or low.startswith("//")

def match_offline_js_catalog_by_url(url: str) -> dict | None:
    target = _normalize_external_js_url(url).lower()
    if not target:
        return None
    parsed = urlparse(target)
    host_path = f"{parsed.netloc}{parsed.path}".lower()
    basename = Path(parsed.path).name.lower()
    if basename:
        for entry in OFFLINE_JS_LIB_CATALOG:
            filename = str(entry.get("filename", "") or "").strip().lower()
            if filename and basename == filename:
                return entry
    for entry in OFFLINE_JS_LIB_CATALOG:
        tokens = [str(x).strip().lower() for x in (entry.get("match_tokens") or []) if str(x).strip()]
        if tokens and any(token in target or token in host_path for token in tokens):
            return entry
    return None

def cache_external_js_url(js_root: Path, url: str) -> tuple[Path | None, str]:
    target_url = _normalize_external_js_url(url)
    if not target_url:
        return None, "empty-url"
    parsed = urlparse(target_url)
    base = Path(parsed.path).name.strip()
    if not base or "." not in base:
        h = _sha256_bytes(target_url.encode("utf-8"))[:10]
        base = f"external_{h}.js"
    fname = _safe_js_filename(base, "external.js")
    ext_root = (js_root / "external").resolve()
    ext_root.mkdir(parents=True, exist_ok=True)
    target = ext_root / fname
    if target.exists() and target.stat().st_size > 40:
        return target, "cached"
    try:
        data, _ = _download_http_bytes(target_url, timeout=35.0)
        if len(data) < 40:
            return None, "download-too-small"
        probe = data[:1024].decode("utf-8", errors="ignore").lower()
        if "<html" in probe and "<script" not in probe:
            return None, "unexpected-html-payload"
        if target.exists() and target.stat().st_size > 0:
            digest_now = _sha256_bytes(data)
            digest_old = _sha256_file(target)
            if digest_now != digest_old:
                stem = target.stem
                suffix = target.suffix or ".js"
                target = ext_root / f"{stem}_{digest_now[:8]}{suffix}"
        target.write_bytes(data)
        return target, "downloaded"
    except Exception as exc:
        return None, trim(str(exc), 220)

def trim(text: object, limit: int = MAX_TOOL_OUTPUT) -> str:
    s = str(text)
    return s if len(s) <= limit else s[:limit] + "\n...(truncated)"


def _fmt_export_ts(ts: float | int) -> str:
    v = float(ts or 0)
    if v <= 0:
        return ""
    try:
        from datetime import datetime
        return datetime.fromtimestamp(v).strftime("%Y-%m-%d %H:%M:%S")
    except Exception:
        return ""


def _html_esc(text: str) -> str:
    return html.escape(str(text or ""))


def _text_to_minimal_pdf(text: str) -> bytes:
    """纯 Python 最小 PDF 生成器，支持 CJK（中日韩）字符。"""
    raw = str(text or "")
    lines = raw.replace("\r\n", "\n").replace("\r", "\n").split("\n")
    font_size = 9
    leading = font_size * 1.5
    margin_top, margin_bottom, margin_left, margin_right = 50, 50, 50, 50
    page_w, page_h = 595, 842  # A4

    def _has_cjk(s: str) -> bool:
        for ch in s:
            cp = ord(ch)
            if (0x2E80 <= cp <= 0x9FFF or 0xF900 <= cp <= 0xFAFF
                    or 0xFE30 <= cp <= 0xFE4F or 0x20000 <= cp <= 0x2FA1F
                    or 0x3000 <= cp <= 0x30FF or 0x31F0 <= cp <= 0x31FF
                    or 0xFF00 <= cp <= 0xFFEF):
                return True
        return False

    has_cjk = _has_cjk(raw)

    # CJK chars are wider; adjust chars-per-line accordingly
    usable_w = page_w - margin_left - margin_right
    if has_cjk:
        max_chars_per_line = max(20, int(usable_w / (font_size * 0.55)))
    else:
        max_chars_per_line = max(20, int(usable_w / (font_size * 0.52)))
    usable_h = page_h - margin_top - margin_bottom
    lines_per_page = max(1, int(usable_h / leading))

    # 折行
    wrapped: list[str] = []
    for line in lines:
        if not line:
            wrapped.append("")
            continue
        while len(line) > max_chars_per_line:
            wrapped.append(line[:max_chars_per_line])
            line = line[max_chars_per_line:]
        wrapped.append(line)

    # 分页
    pages_list: list[list[str]] = []
    for i in range(0, len(wrapped), lines_per_page):
        pages_list.append(wrapped[i:i + lines_per_page])
    if not pages_list:
        pages_list = [[""]]

    def _pdf_escape_bytes(s: str) -> bytes:
        """Encode string to UTF-16BE hex for CJK-safe PDF text."""
        encoded = s.encode("utf-16-be")
        return b"<FEFF" + encoded.hex().upper().encode("ascii") + b">"

    def _pdf_escape_latin(s: str) -> str:
        safe = s.replace("\\", "\\\\").replace("(", "\\(").replace(")", "\\)")
        return safe.encode("latin-1", errors="replace").decode("latin-1")

    objects: list[bytes] = []
    offsets: list[int] = []
    buf = b"%PDF-1.4\n%\xe2\xe3\xcf\xd3\n"

    def add_obj_bytes(content: bytes) -> int:
        nonlocal buf
        idx = len(objects) + 1
        offsets.append(len(buf))
        obj_bytes = f"{idx} 0 obj\n".encode("ascii") + content + b"\nendobj\n"
        buf += obj_bytes
        objects.append(obj_bytes)
        return idx

    def add_obj(content: str) -> int:
        return add_obj_bytes(content.encode("latin-1", errors="replace"))

    catalog_id = add_obj("<< /Type /Catalog /Pages 2 0 R >>")
    add_obj("PAGES_PLACEHOLDER")  # obj 2: replaced after page generation

    if has_cjk:
        # CIDFont for CJK support using Adobe-GB1 (Simplified Chinese) as primary
        # with fallback ordering — most PDF viewers can render CJK with this
        cid_font_id = add_obj(
            "<< /Type /Font /Subtype /Type0 /BaseFont /STSong-Light "
            "/Encoding /UniGB-UTF16-H "
            "/DescendantFonts [<< /Type /Font /Subtype /CIDFontType0 "
            "/BaseFont /STSong-Light "
            "/CIDSystemInfo << /Registry (Adobe) /Ordering (GB1) /Supplement 5 >> "
            "/DW 1000 >>] >>"
        )
        # Also add a latin fallback font for ASCII-heavy sections
        latin_font_id = add_obj("<< /Type /Font /Subtype /Type1 /BaseFont /Courier /Encoding /WinAnsiEncoding >>")
    else:
        latin_font_id = add_obj("<< /Type /Font /Subtype /Type1 /BaseFont /Courier /Encoding /WinAnsiEncoding >>")
        cid_font_id = 0

    page_ids: list[int] = []
    for page_lines in pages_list:
        stream_parts: list[bytes] = []
        stream_parts.append(b"BT\n")
        y = page_h - margin_top
        stream_parts.append(f"{margin_left} {y} Td\n".encode("ascii"))
        for pl in page_lines:
            if has_cjk and _has_cjk(pl):
                stream_parts.append(f"/F1 {font_size} Tf\n".encode("ascii"))
                stream_parts.append(_pdf_escape_bytes(pl) + b" Tj\n")
            else:
                font_tag = "/F2" if has_cjk else "/F1"
                stream_parts.append(f"{font_tag} {font_size} Tf\n".encode("ascii"))
                safe = _pdf_escape_latin(pl)
                stream_parts.append(f"({safe}) Tj\n".encode("latin-1", errors="replace"))
            stream_parts.append(f"0 -{leading:.1f} Td\n".encode("ascii"))
        stream_parts.append(b"ET")
        stream_bytes = b"".join(stream_parts)
        content_id = add_obj_bytes(
            f"<< /Length {len(stream_bytes)} >>\nstream\n".encode("ascii")
            + stream_bytes
            + b"\nendstream"
        )
        if has_cjk:
            font_dict = f"/F1 {cid_font_id} 0 R /F2 {latin_font_id} 0 R"
        else:
            font_dict = f"/F1 {latin_font_id} 0 R"
        page_id = add_obj(
            f"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 {page_w} {page_h}] "
            f"/Contents {content_id} 0 R /Resources << /Font << {font_dict} >> >> >>"
        )
        page_ids.append(page_id)

    kids = " ".join(f"{pid} 0 R" for pid in page_ids)
    pages_content = f"<< /Type /Pages /Kids [{kids}] /Count {len(page_ids)} >>"
    pages_bytes = f"2 0 obj\n{pages_content}\nendobj\n".encode("latin-1")
    old_pages = objects[1]
    buf = buf.replace(b"2 0 obj\nPAGES_PLACEHOLDER\nendobj\n", pages_bytes)
    size_diff = len(pages_bytes) - len(old_pages)
    for i in range(2, len(offsets)):
        offsets[i] += size_diff

    xref_offset = len(buf)
    buf += b"xref\n"
    buf += f"0 {len(objects) + 1}\n".encode("ascii")
    buf += b"0000000000 65535 f \n"
    for off in offsets:
        buf += f"{off:010d} 00000 n \n".encode("ascii")
    buf += b"trailer\n"
    buf += f"<< /Size {len(objects) + 1} /Root {catalog_id} 0 R >>\n".encode("ascii")
    buf += b"startxref\n"
    buf += f"{xref_offset}\n".encode("ascii")
    buf += b"%%EOF\n"
    return buf

def compress_text_blob(text: str) -> str:
    src = str(text or "")
    if not src:
        return ""
    raw = src.encode("utf-8")
    return base64.b64encode(zlib.compress(raw, 6)).decode("ascii")

def decompress_text_blob(blob_b64: str) -> str:
    token = str(blob_b64 or "").strip()
    if not token:
        return ""
    try:
        raw = base64.b64decode(token.encode("ascii"))
        return zlib.decompress(raw).decode("utf-8", errors="replace")
    except Exception:
        return ""

def normalize_work_text(text: object, status: str = "") -> str:
    s = re.sub(r"\s+", " ", str(text or "")).strip()
    if not s:
        return ""
    s = re.sub(r"^\[[ x>\-]\]\s*", "", s, flags=re.IGNORECASE)
    s = re.sub(
        r"^(pending|in[_\-\s]?progress|completed|done|blocked)\s*[·:\-\]]\s*",
        "",
        s,
        flags=re.IGNORECASE,
    )
    if status:
        status_pattern = re.escape(status).replace("_", r"[_\-\s]?")
        s = re.sub(
            rf"\s*[—-]\s*{status_pattern}\s*$",
            "",
            s,
            flags=re.IGNORECASE,
        )
    s = re.sub(
        r"\s*[—-]\s*(pending|in[_\-\s]?progress|completed|done|blocked)\s*$",
        "",
        s,
        flags=re.IGNORECASE,
    )
    return s.strip(" -")

def parse_tool_arguments(raw: object) -> dict:
    if isinstance(raw, dict):
        return raw
    if isinstance(raw, str):
        try:
            parsed = json.loads(raw)
            return parsed if isinstance(parsed, dict) else {}
        except Exception:
            return {}
    return {}

def repair_truncated_json_object(raw: object) -> str:
    src = str(raw or "").strip()
    if not src:
        return ""
    fenced = re.search(r"```(?:json)?\s*([\s\S]*?)```", src, re.IGNORECASE)
    if fenced:
        src = str(fenced.group(1) or "").strip()
    first_obj = src.find("{")
    if first_obj > 0:
        src = src[first_obj:]
    src = src.strip()
    if not src:
        return ""
    if src.endswith(":"):
        src += " null"
    src = re.sub(r",\s*$", "", src)
    if "\n" in src and re.search(r"[,:\[{(\"'`]$", src.rstrip()):
        src = src[: src.rfind("\n")].rstrip()
    if not src:
        return ""
    stack: list[str] = []
    in_string = False
    escaped = False
    for ch in src:
        if in_string:
            if escaped:
                escaped = False
                continue
            if ch == "\\":
                escaped = True
                continue
            if ch == "\"":
                in_string = False
            continue
        if ch == "\"":
            in_string = True
            continue
        if ch in "{[":
            stack.append(ch)
            continue
        if ch == "}" and stack and stack[-1] == "{":
            stack.pop()
            continue
        if ch == "]" and stack and stack[-1] == "[":
            stack.pop()
            continue
    if in_string:
        src += "\""
    src = re.sub(r",\s*$", "", src)
    while stack:
        opener = stack.pop()
        src += "}" if opener == "{" else "]"
    src = re.sub(r",(\s*[}\]])", r"\1", src)
    return src.strip()

def parse_tool_arguments_with_error(raw: object) -> tuple[dict, str]:
    if isinstance(raw, dict):
        return raw, ""
    if isinstance(raw, str):
        text = raw.strip()
        if not text:
            return {}, "arguments is empty string"
        try:
            parsed = json.loads(text)
            if isinstance(parsed, dict):
                return parsed, ""
            return {}, f"arguments JSON is {type(parsed).__name__}, expected object"
        except Exception as exc:
            repaired = repair_truncated_json_object(text)
            if repaired and repaired != text:
                try:
                    parsed_repaired = json.loads(repaired)
                    if isinstance(parsed_repaired, dict):
                        return parsed_repaired, "arguments JSON auto-repaired from invalid/truncated input"
                except Exception:
                    pass
            brief = trim(text.replace("\n", "\\n"), 240)
            return {}, f"arguments JSON parse failed: {exc}; raw={brief}"
    return {}, f"unsupported arguments type: {type(raw).__name__}"

def probe_ollama_environment(base_url: str, timeout: int = 4) -> tuple[bool, list[str], str]:
    url = f"{str(base_url or '').rstrip('/')}/api/tags"
    req = Request(url, method="GET")
    try:
        with urlopen(req, timeout=timeout) as resp:
            raw = json.loads(resp.read().decode("utf-8"))
        tags: list[str] = []
        for item in raw.get("models", []):
            name = item.get("name")
            if isinstance(name, str) and name.strip():
                tags.append(name.strip())
        return True, tags, ""
    except Exception as exc:
        return False, [], str(exc)

def list_ollama_models(base_url: str, timeout: int = 4) -> list[str]:
    ok, tags, _ = probe_ollama_environment(base_url, timeout=timeout)
    return tags if ok else []

_OLLAMA_TAG_CACHE_LOCK = threading.Lock()
_OLLAMA_TAG_CACHE: dict[str, dict] = {}


class EmptyActionError(RuntimeError):
    """Raised when assistant returns only thinking but no actionable output."""


class CircuitBreakerTriggered(RuntimeError):
    """Raised when fused fault counter reaches hard break threshold."""

def list_ollama_models_cached(base_url: str, ttl_seconds: int = 30, force_refresh: bool = False) -> list[str]:
    key = str(base_url or "").rstrip("/")
    now = time.time()
    cached_tags: list[str] = []
    with _OLLAMA_TAG_CACHE_LOCK:
        row = _OLLAMA_TAG_CACHE.get(key)
        if row:
            tags = row.get("tags", [])
            cached_tags = list(tags) if isinstance(tags, list) else []
        if (not force_refresh) and row and (now - float(row.get("ts", 0.0))) <= ttl_seconds:
            return list(cached_tags)
    ok, tags, _ = probe_ollama_environment(base_url)
    if ok:
        with _OLLAMA_TAG_CACHE_LOCK:
            _OLLAMA_TAG_CACHE[key] = {"ts": now, "tags": list(tags)}
        return list(tags)
    if cached_tags:
        return list(cached_tags)
    with _OLLAMA_TAG_CACHE_LOCK:
        _OLLAMA_TAG_CACHE[key] = {"ts": now, "tags": []}
    return []

def resolve_ollama_model(base_url: str, preferred: str) -> str:
    models = list_ollama_models(base_url)
    if not models:
        return preferred
    if preferred in models:
        return preferred
    lowered = [(m, m.lower()) for m in models]
    for m, low in lowered:
        if "coder" in low or "code" in low:
            return m
    return models[0]

def infer_thinking_model(model: str) -> bool:
    # Thinking control is disabled globally: do not infer or force it by model name.
    return False

def split_thinking_content(text: str) -> tuple[str, str]:
    if not text:
        return "", ""
    src = str(text)
    thinking_parts: list[str] = []

    def _collect(group_text: str):
        s = str(group_text or "").strip()
        if s:
            thinking_parts.append(s)

    def _repl_block(m: re.Match) -> str:
        _collect(m.group(1))
        return ""

    # Scan <think> blocks leniently: if closing tag is missing, treat tail as thinking.
    body_parts: list[str] = []
    pos = 0
    while pos < len(src):
        open_m = re.search(r"(?is)<think\b[^>]*>", src[pos:])
        if not open_m:
            body_parts.append(src[pos:])
            break
        open_start = pos + open_m.start()
        open_end = pos + open_m.end()
        body_parts.append(src[pos:open_start])
        close_m = re.search(r"(?is)</think\s*>", src[open_end:])
        if close_m:
            close_start = open_end + close_m.start()
            close_end = open_end + close_m.end()
            _collect(src[open_end:close_start])
            pos = close_end
            continue
        _collect(src[open_end:])
        pos = len(src)
        break
    body = "".join(body_parts)
    body = re.sub(r"(?is)```(?:thinking|reasoning)\s*([\s\S]*?)```", _repl_block, body)
    body = re.sub(r"(?is)<\|start_of_thought\|>(.*?)<\|end_of_thought\|>", _repl_block, body)
    body = re.sub(r"\n{3,}", "\n\n", body).strip()
    thinking = "\n\n".join(part for part in thinking_parts if part).strip()
    return body, trim(thinking, 24_000) if thinking else ""

def strip_thinking_content(text: str) -> str:
    return split_thinking_content(text)[0]

def check_ollama_model_ready(base_url: str, model: str, timeout: int = 10) -> tuple[bool, str]:
    if not model:
        return False, "model required"
    url = f"{base_url.rstrip('/')}/api/show"
    payload = {
        "name": model,
    }
    req = Request(
        url,
        data=json_dumps(payload).encode("utf-8"),
        headers={"Content-Type": "application/json"},
        method="POST",
    )
    try:
        with urlopen(req, timeout=timeout) as resp:
            _ = resp.read()
        return True, ""
    except HTTPError as exc:
        text = exc.read().decode("utf-8", errors="replace")
        low = text.lower()
        if exc.code == 404 or "not found" in low:
            return False, f"not found: {model}"
        return False, f"HTTP {exc.code}: {text}"
    except Exception as exc:
        return False, str(exc)

def list_loaded_ollama_models(base_url: str, timeout: int = 5) -> list[str]:
    url = f"{str(base_url or '').rstrip('/')}/api/ps"
    req = Request(url, method="GET")
    try:
        with urlopen(req, timeout=timeout) as resp:
            raw = json.loads(resp.read().decode("utf-8"))
        out: list[str] = []
        for item in raw.get("models", []) if isinstance(raw, dict) else []:
            name = str(item.get("name", "") or "").strip()
            if name:
                out.append(name)
        return out
    except Exception:
        return []

def wake_ollama_model(base_url: str, model: str, timeout: int = 30) -> tuple[bool, str]:
    target = str(model or "").strip()
    if not target:
        return False, "model required"
    url = f"{str(base_url or '').rstrip('/')}/api/generate"
    payload = {
        "model": target,
        "prompt": "ping",
        "stream": False,
        "keep_alive": "20m",
        "options": {"num_predict": 1, "temperature": 0},
    }
    req = Request(
        url,
        data=json_dumps(payload).encode("utf-8"),
        headers={"Content-Type": "application/json"},
        method="POST",
    )
    try:
        with urlopen(req, timeout=timeout) as resp:
            text = resp.read().decode("utf-8", errors="replace")
        obj = parse_json_object(text, {})
        err = str(obj.get("error", "")).strip() if isinstance(obj, dict) else ""
        if err:
            return False, trim(err, 180)
        return True, "warmed"
    except HTTPError as exc:
        text = exc.read().decode("utf-8", errors="replace")
        return False, f"HTTP {exc.code}: {trim(text, 180)}"
    except Exception as exc:
        return False, trim(str(exc), 180)

def try_pull_ollama_model(model: str, timeout: int = 180) -> tuple[bool, str]:
    cli = shutil.which("ollama")
    if not cli:
        return False, "ollama CLI not found"
    try:
        r = subprocess.run(
            [cli, "pull", model],
            capture_output=True,
            text=True,
            timeout=timeout,
        )
        output = trim((r.stdout + r.stderr).strip() or "(no output)", 1200)
        if r.returncode == 0:
            return True, f"pulled model '{model}'"
        return False, f"pull failed for '{model}': {output}"
    except subprocess.TimeoutExpired:
        return False, f"pull timeout for '{model}' ({timeout}s)"
    except Exception as exc:
        return False, f"pull failed for '{model}': {exc}"

def ordered_model_candidates(base_url: str, preferred: str, exclude: set[str] | None = None) -> list[str]:
    blocked = set(exclude or set())
    models = list_ollama_models(base_url)
    out = []
    if preferred and preferred not in blocked:
        out.append(preferred)
    ranked = [m for m in models if m not in blocked and m != preferred]
    ranked.sort(key=lambda m: (0 if ("coder" in m.lower() or "code" in m.lower()) else 1, m.lower()))
    out.extend(ranked)
    if not out and preferred and preferred not in blocked:
        out.append(preferred)
    dedup = []
    seen = set()
    for item in out:
        if item in seen:
            continue
        seen.add(item)
        dedup.append(item)
    return dedup

def pick_working_ollama_model(
    base_url: str,
    preferred: str,
    *,
    exclude: set[str] | None = None,
    timeout: int = 10,
    max_candidates: int = 6,
) -> tuple[str | None, str]:
    errors = []
    candidates = ordered_model_candidates(base_url, preferred, exclude)[: max(1, int(max_candidates))]
    for candidate in candidates:
        ok, err = check_ollama_model_ready(base_url, candidate, timeout=timeout)
        if ok:
            return candidate, ""
        if err:
            errors.append(f"{candidate}: {err}")
    return None, "; ".join(errors)

def parse_json_object(text: str, default: dict | None = None) -> dict:
    try:
        obj = json.loads(text)
        return obj if isinstance(obj, dict) else (default or {})
    except Exception:
        return default or {}

def extract_json_object_from_text(text: str, default: dict | None = None) -> dict:
    src = str(text or "").strip()
    if not src:
        return default or {}
    direct = parse_json_object(src, {})
    if direct:
        return direct
    fence = re.search(r"```json\s*(\{.*?\})\s*```", src, re.S | re.I)
    if fence:
        boxed = parse_json_object(fence.group(1), {})
        if boxed:
            return boxed
    decoder = json.JSONDecoder()
    for i, ch in enumerate(src):
        if ch != "{":
            continue
        try:
            obj, _ = decoder.raw_decode(src[i:])
        except Exception:
            continue
        if isinstance(obj, dict):
            return obj
    return default or {}

def extract_base_url(endpoint_or_base: str) -> str:
    s = (endpoint_or_base or "").strip()
    if not s:
        return ""
    low = s.lower()
    for suffix in ("/v1/chat/completions", "/chat/completions"):
        if low.endswith(suffix):
            return s[: -len(suffix)] or s
    return s

def complete_chat_endpoint(endpoint_or_base: str) -> str:
    s = (endpoint_or_base or "").strip()
    if not s:
        return ""
    low = s.lower()
    if low.endswith("/chat/completions") or low.endswith("/v1/chat/completions"):
        return s
    if low.endswith("/v1"):
        return s.rstrip("/") + "/chat/completions"
    return s.rstrip("/") + "/v1/chat/completions"

def _is_http_url(text: str) -> bool:
    try:
        p = urlparse(str(text or "").strip())
        return p.scheme.lower() in {"http", "https"}
    except Exception:
        return False

def _resolve_local_path(raw: str, base_dir: Path) -> Path:
    src = str(raw or "").strip()
    if not src:
        raise ValueError("empty path")
    p = urlparse(src)
    if p.scheme.lower() == "file":
        file_part = unquote(p.path or "")
        if p.netloc:
            file_part = f"/{p.netloc}{file_part}"
        path = Path(file_part)
    else:
        path = Path(src).expanduser()
    if not path.is_absolute():
        path = (base_dir / path).resolve()
    else:
        path = path.resolve()
    return path

def load_llm_config_from_source(source: str, *, base_dir: Path = WORKDIR, timeout: int = 20) -> tuple[dict, str]:
    raw = str(source or "").strip()
    if not raw:
        raise ValueError("config source is required")
    text = ""
    source_desc = raw
    if _is_http_url(raw):
        req = Request(raw, method="GET")
        try:
            with urlopen(req, timeout=max(3, int(timeout))) as resp:
                text = resp.read().decode("utf-8", errors="replace")
        except HTTPError as exc:
            body = exc.read().decode("utf-8", errors="replace")
            raise ValueError(f"failed to fetch config URL ({exc.code}): {trim(body, 240)}") from exc
        except URLError as exc:
            raise ValueError(f"failed to fetch config URL: {exc}") from exc
    else:
        path = _resolve_local_path(raw, base_dir)
        if not path.exists() or not path.is_file():
            raise ValueError(f"config file not found: {path}")
        try:
            text = path.read_text(encoding="utf-8")
        except Exception as exc:
            raise ValueError(f"failed to read config file: {path} ({exc})") from exc
        source_desc = str(path)

    config = parse_json_object(text, {})
    if not config:
        raise ValueError(f"invalid JSON config: {source_desc}")
    if not looks_like_llm_config(config):
        keys = sorted(str(k) for k in config.keys())[:16]
        raise ValueError(
            f"config does not look like LLM config: {source_desc} (keys={keys})"
        )
    return config, source_desc

def parse_llm_config_profiles(config: dict, default_ollama_url: str, default_ollama_model: str) -> dict:
    model_caps_map = config.get("model_capabilities", {})
    if isinstance(model_caps_map, str):
        model_caps_map = parse_json_object(model_caps_map, {})
    if not isinstance(model_caps_map, dict):
        model_caps_map = {}

    raw_global_caps = config.get("multimodal_capabilities", config.get("capabilities", {}))
    if isinstance(raw_global_caps, str):
        raw_global_caps = parse_json_object(raw_global_caps, {})
    if not isinstance(raw_global_caps, dict):
        raw_global_caps = {}

    raw_global_media_endpoints = config.get("media_endpoints", {})
    if isinstance(raw_global_media_endpoints, str):
        raw_global_media_endpoints = parse_json_object(raw_global_media_endpoints, {})
    if not isinstance(raw_global_media_endpoints, dict):
        raw_global_media_endpoints = {}

    def build_profile_capabilities(provider_key: str, provider: str, model: str) -> dict[str, bool]:
        caps = infer_model_multimodal_capabilities(provider, model)
        if any(k in raw_global_caps for k in MEDIA_CAPABILITY_KEYS):
            caps = merge_multimodal_capabilities(caps, parse_capability_overrides(raw_global_caps))
        nested_global = raw_global_caps.get(provider_key)
        if nested_global is not None:
            caps = merge_multimodal_capabilities(caps, parse_capability_overrides(nested_global))
        direct_override = config.get(f"{provider_key}_capabilities")
        if direct_override is not None:
            caps = merge_multimodal_capabilities(caps, parse_capability_overrides(direct_override))
        model_override = model_caps_map.get(model) or model_caps_map.get(str(model or "").lower())
        if model_override is not None:
            caps = merge_multimodal_capabilities(caps, parse_capability_overrides(model_override))
        return caps

    def build_profile_media_endpoints(provider_key: str) -> dict[str, str]:
        out: dict[str, str] = {}
        if any(k in raw_global_media_endpoints for k in ("image", "audio", "video")):
            out.update(parse_media_endpoints(raw_global_media_endpoints))
        nested = raw_global_media_endpoints.get(provider_key)
        if nested is not None:
            out.update(parse_media_endpoints(nested))
        direct = config.get(f"{provider_key}_media_endpoints")
        if direct is not None:
            out.update(parse_media_endpoints(direct))
        for media_type in ("image", "audio", "video"):
            specific = str(config.get(f"{provider_key}_{media_type}_endpoint", "") or "").strip()
            if specific:
                out[media_type] = specific
        return out

    def add_profile(
        out: list[dict],
        *,
        profile_id: str,
        provider: str,
        label: str,
        model: str = "",
        base_url: str = "",
        endpoint: str = "",
        api_key: str = "",
        headers: dict | None = None,
        payload_template: str = "",
        thinking_stream: bool = False,
        temperature: float = 0.2,
        request_timeout: int = DEFAULT_REQUEST_TIMEOUT,
        capabilities: dict | None = None,
        media_endpoints: dict | None = None,
        source: str = "config",
    ):
        out.append(
            {
                "id": profile_id,
                "provider": provider,
                "label": label,
                "model": (model or "").strip(),
                "base_url": (base_url or "").strip(),
                "endpoint": (endpoint or "").strip(),
                "api_key": (api_key or "").strip(),
                "headers": headers or {},
                "payload_template": payload_template or "",
                "thinking_stream": bool(thinking_stream),
                "temperature": float(temperature or 0.2),
                "request_timeout": normalize_timeout_seconds(
                    request_timeout,
                    minimum=MIN_TIMEOUT_SECONDS,
                    maximum=MAX_TIMEOUT_SECONDS,
                    fallback=DEFAULT_REQUEST_TIMEOUT,
                ),
                "capabilities": capabilities or default_multimodal_capabilities(),
                "media_endpoints": media_endpoints or {},
                "source": source,
            }
        )

    profiles: list[dict] = []
    provider = str(config.get("provider", "")).strip().lower()
    temp = float(config.get("temperature", 0.2) or 0.2)
    timeout = normalize_timeout_seconds(
        config.get("request_timeout", DEFAULT_REQUEST_TIMEOUT),
        minimum=MIN_TIMEOUT_SECONDS,
        maximum=MAX_TIMEOUT_SECONDS,
        fallback=DEFAULT_REQUEST_TIMEOUT,
    )
    thinking_stream_default = bool(
        config.get("thinking_stream", config.get("stream_thinking", False))
    )

    ollama_url = str(config.get("ollama_url", default_ollama_url)).strip() or default_ollama_url
    ollama_model = str(config.get("ollama_model", default_ollama_model)).strip() or default_ollama_model
    add_profile(
        profiles,
        profile_id="ollama",
        provider="ollama",
        label="Ollama",
        model=ollama_model,
        base_url=extract_base_url(ollama_url),
        thinking_stream=bool(config.get("ollama_thinking_stream", thinking_stream_default)),
        temperature=temp,
        request_timeout=timeout,
        capabilities=build_profile_capabilities("ollama", "ollama", ollama_model),
        media_endpoints=build_profile_media_endpoints("ollama"),
    )

    openai_url = str(config.get("openai_url", "")).strip()
    openai_model = str(config.get("openai_model", "")).strip()
    openai_key = str(config.get("openai_key", "")).strip()
    if openai_url or openai_model or openai_key:
        add_profile(
            profiles,
            profile_id="openai",
            provider="openai_compat",
            label="OpenAI Compatible",
            model=openai_model or "gpt-4o-mini",
            base_url=extract_base_url(openai_url),
            endpoint=complete_chat_endpoint(openai_url),
            api_key=openai_key,
            thinking_stream=bool(config.get("openai_thinking_stream", thinking_stream_default)),
            temperature=temp,
            request_timeout=timeout,
            capabilities=build_profile_capabilities("openai", "openai_compat", openai_model or "gpt-4o-mini"),
            media_endpoints=build_profile_media_endpoints("openai"),
        )

    sf_url = str(config.get("siliconflow_url", "")).strip()
    sf_model = str(config.get("siliconflow_model", "")).strip()
    sf_key = str(config.get("siliconflow_key", "")).strip()
    if sf_url or sf_model or sf_key:
        add_profile(
            profiles,
            profile_id="siliconflow",
            provider="openai_compat",
            label="SiliconFlow",
            model=sf_model or "Qwen/Qwen3-Next-80B-A3B-Instruct",
            base_url=extract_base_url(sf_url),
            endpoint=complete_chat_endpoint(sf_url),
            api_key=sf_key,
            thinking_stream=bool(config.get("siliconflow_thinking_stream", thinking_stream_default)),
            temperature=temp,
            request_timeout=timeout,
            capabilities=build_profile_capabilities("siliconflow", "openai_compat", sf_model or "Qwen/Qwen3-Next-80B-A3B-Instruct"),
            media_endpoints=build_profile_media_endpoints("siliconflow"),
        )

    custom_url = str(config.get("custom_url", "")).strip()
    custom_key = str(config.get("custom_key", "")).strip()
    custom_headers = parse_json_object(str(config.get("custom_headers", "{}") or "{}"), {})
    custom_payload = str(config.get("custom_payload", "") or "").strip()
    if custom_url:
        add_profile(
            profiles,
            profile_id="custom",
            provider="custom_http",
            label="Custom HTTP",
            model=str(config.get("custom_model", "") or config.get("openai_model", "") or "custom-model"),
            base_url=extract_base_url(custom_url),
            endpoint=custom_url,
            api_key=custom_key,
            headers=custom_headers,
            payload_template=custom_payload,
            thinking_stream=bool(config.get("custom_thinking_stream", thinking_stream_default)),
            temperature=temp,
            request_timeout=timeout,
            capabilities=build_profile_capabilities("custom", "custom_http", str(config.get("custom_model", "") or config.get("openai_model", "") or "custom-model")),
            media_endpoints=build_profile_media_endpoints("custom"),
        )

    if not profiles:
        add_profile(
            profiles,
            profile_id="ollama",
            provider="ollama",
            label="Ollama",
            model=default_ollama_model,
            base_url=default_ollama_url,
            thinking_stream=thinking_stream_default,
            temperature=0.2,
            request_timeout=DEFAULT_REQUEST_TIMEOUT,
            capabilities=build_profile_capabilities("ollama", "ollama", default_ollama_model),
            media_endpoints=build_profile_media_endpoints("ollama"),
            source="default",
        )

    active_map = {
        "ollama": "ollama",
        "openai": "openai",
        "siliconflow": "siliconflow",
        "custom": "custom",
    }
    default_profile_id = active_map.get(provider, profiles[0]["id"])
    return {"profiles": profiles, "default_profile_id": default_profile_id}

def looks_like_llm_config(config: dict) -> bool:
    if not isinstance(config, dict) or not config:
        return False
    keys = {str(k).strip().lower() for k in config.keys()}
    markers = {
        "provider",
        "ollama_url",
        "ollama_model",
        "openai_url",
        "openai_model",
        "openai_key",
        "siliconflow_url",
        "siliconflow_model",
        "siliconflow_key",
        "custom_url",
        "custom_model",
        "custom_key",
        "custom_headers",
        "custom_payload",
        "capabilities",
        "multimodal_capabilities",
        "model_capabilities",
        "media_endpoints",
        "ollama_capabilities",
        "openai_capabilities",
        "siliconflow_capabilities",
        "custom_capabilities",
        "ollama_media_endpoints",
        "openai_media_endpoints",
        "siliconflow_media_endpoints",
        "custom_media_endpoints",
        "ollama_image_endpoint",
        "ollama_audio_endpoint",
        "ollama_video_endpoint",
        "openai_image_endpoint",
        "openai_audio_endpoint",
        "openai_video_endpoint",
        "siliconflow_image_endpoint",
        "siliconflow_audio_endpoint",
        "siliconflow_video_endpoint",
        "custom_image_endpoint",
        "custom_audio_endpoint",
        "custom_video_endpoint",
        "temperature",
        "request_timeout",
    }
    return bool(keys & markers)

def user_id_from_ip(ip: str) -> str:
    raw = str(ip or "").strip()
    if raw.lower().startswith("::ffff:"):
        raw = raw.split("::ffff:", 1)[1].strip()
    token = hashlib.sha256(raw.encode("utf-8")).hexdigest()[:12]
    safe_ip = re.sub(r"[^A-Za-z0-9._-]", "_", raw)
    return f"user_{safe_ip}_{token}"

class CryptoBox:
    def __init__(self, codes_root: Path):
        self.codes_root = codes_root
        self.codes_root.mkdir(parents=True, exist_ok=True)
        self.key_file = self.codes_root / ".encryption_key"
        self.key = self._load_or_create_key()

    def _load_or_create_key(self) -> bytes:
        if self.key_file.exists():
            raw = self.key_file.read_text(encoding="utf-8").strip()
            if raw:
                return bytes.fromhex(raw)
        key = os.urandom(32)
        self.key_file.write_text(key.hex(), encoding="utf-8")
        return key

    def _stream_xor(self, data: bytes, nonce: bytes) -> bytes:
        out = bytearray(len(data))
        counter = 0
        offset = 0
        while offset < len(data):
            block = hashlib.sha256(self.key + nonce + counter.to_bytes(8, "big")).digest()
            n = min(32, len(data) - offset)
            for i in range(n):
                out[offset + i] = data[offset + i] ^ block[i]
            offset += n
            counter += 1
        return bytes(out)

    def encrypt_text(self, text: str) -> str:
        payload = text.encode("utf-8")
        nonce = os.urandom(16)
        ct = self._stream_xor(payload, nonce)
        mac = hmac.new(self.key, nonce + ct, hashlib.sha256).hexdigest()
        box = {
            "v": 1,
            "n": base64.b64encode(nonce).decode("ascii"),
            "c": base64.b64encode(ct).decode("ascii"),
            "m": mac,
        }
        return json_dumps(box)

    def decrypt_text(self, box_text: str) -> str:
        box = json.loads(box_text)
        if not isinstance(box, dict) or "n" not in box or "c" not in box or "m" not in box:
            return box_text
        nonce = base64.b64decode(box["n"])
        ct = base64.b64decode(box["c"])
        mac = hmac.new(self.key, nonce + ct, hashlib.sha256).hexdigest()
        if not hmac.compare_digest(mac, box["m"]):
            raise ValueError("Encrypted payload integrity check failed")
        pt = self._stream_xor(ct, nonce)
        return pt.decode("utf-8")

    def write_json(self, path: Path, obj: object):
        path.parent.mkdir(parents=True, exist_ok=True)
        enc = self.encrypt_text(json_dumps(obj, indent=2))
        bak = path.with_name(f"{path.name}.bak")
        tmp = path.with_name(f".{path.name}.{uuid.uuid4().hex}.tmp")
        try:
            with tmp.open("w", encoding="utf-8") as f:
                f.write(enc)
                f.flush()
                os.fsync(f.fileno())
            if path.exists():
                try:
                    os.replace(path, bak)
                except Exception:
                    try:
                        shutil.copy2(path, bak)
                    except Exception:
                        pass
            os.replace(tmp, path)
        finally:
            try:
                if tmp.exists():
                    tmp.unlink()
            except Exception:
                pass

    def read_json(self, path: Path, default: object) -> object:
        bak = path.with_name(f"{path.name}.bak")
        candidates: list[Path] = [path, bak]
        seen: set[str] = set()
        for fp in candidates:
            key = str(fp)
            if key in seen:
                continue
            seen.add(key)
            if not fp.exists():
                continue
            try:
                raw = fp.read_text(encoding="utf-8")
            except Exception:
                continue
            try:
                dec = self.decrypt_text(raw)
                return json.loads(dec)
            except Exception:
                try:
                    return json.loads(raw)
                except Exception:
                    continue
        return default

def parse_front_matter(text: str) -> tuple[dict, str]:
    text = text or ""
    if not text.startswith("---\n"):
        return {}, text.strip()
    end = text.find("\n---\n", 4)
    if end < 0:
        return {}, text.strip()
    raw_meta = text[4:end]
    body = text[end + 5 :].strip()
    meta: dict[str, str] = {}
    lines = raw_meta.splitlines()
    i = 0
    while i < len(lines):
        line = lines[i]
        if not line.strip():
            i += 1
            continue
        if ":" in line and not line.startswith((" ", "\t")):
            key, value = line.split(":", 1)
            key = key.strip()
            value = value.strip()
            if value == "|":
                i += 1
                block = []
                while i < len(lines) and lines[i].startswith(("  ", "\t")):
                    block.append(lines[i].lstrip())
                    i += 1
                meta[key] = "\n".join(block).strip()
                continue
            meta[key] = value
        i += 1
    return meta, body

def try_read_text(path: Path, max_bytes: int = 400_000) -> str | None:
    try:
        if not path.exists() or not path.is_file():
            return None
        if path.stat().st_size > max_bytes:
            return None
        return path.read_text(encoding="utf-8")
    except Exception:
        return None

def make_unified_diff(path: str, old_text: str, new_text: str, max_lines: int = 400) -> tuple[str, int, int]:
    old_lines = old_text.splitlines()
    new_lines = new_text.splitlines()
    diff = list(
        difflib.unified_diff(
            old_lines,
            new_lines,
            fromfile=f"a/{path}",
            tofile=f"b/{path}",
            lineterm="",
        )
    )
    added = sum(1 for ln in diff if ln.startswith("+") and not ln.startswith("+++"))
    deleted = sum(1 for ln in diff if ln.startswith("-") and not ln.startswith("---"))
    if max_lines and len(diff) > max_lines:
        diff = diff[:max_lines] + [f"... diff truncated, total lines={len(diff)}"]
    text = "\n".join(diff) if diff else f"@@ no textual diff for {path}"
    return text, added, deleted

def _skip_row(text: str) -> dict:
    msg = str(text or "").strip() or "⋮"
    if not msg.startswith("⋮"):
        msg = f"⋮ {msg}"
    return {"kind": "skip", "sign": "⋮", "old_line": None, "new_line": None, "text": msg}


def _row_is_hot(row: dict) -> bool:
    return str((row or {}).get("kind", "")).strip().lower() in {"add", "delete"}


def _hotspot_index(rows: list[dict]) -> int:
    arr = [dict(x) for x in (rows or [])]
    if not arr:
        return 0
    hot = [1 if _row_is_hot(row) else 0 for row in arr]
    if not any(hot):
        return max(0, len(arr) - 1)
    prefix = [0]
    for v in hot:
        prefix.append(prefix[-1] + v)
    n = len(arr)
    radius = max(10, min(180, n // 18))
    best_idx = 0
    best_score = -1
    for i in range(n):
        a = max(0, i - radius)
        b = min(n - 1, i + radius)
        score = prefix[b + 1] - prefix[a]
        if score > best_score or (score == best_score and i > best_idx):
            best_idx = i
            best_score = score
    return best_idx


def _compress_rows_keep_hotspot(
    rows: list[dict],
    max_rows: int,
    *,
    prefix_omitted: int = 0,
) -> tuple[list[dict], bool]:
    arr = [dict(x) for x in (rows or [])]
    limit = max(1, int(max_rows or 1))
    omitted_prefix_base = max(0, int(prefix_omitted or 0))
    if not arr:
        if omitted_prefix_base <= 0:
            return [], False
        return [_skip_row(f"⋮ ... ({omitted_prefix_base} rows omitted)")], True
    anchor = _hotspot_index(arr)
    n = len(arr)
    slots = (1 if omitted_prefix_base > 0 else 0) + 1
    slots = min(limit - 1, max(0, slots))
    start = 0
    end = n
    for _ in range(3):
        budget = max(1, limit - slots)
        if budget >= n:
            start, end = 0, n
        else:
            start = max(0, anchor - (budget // 2))
            if start + budget > n:
                start = max(0, n - budget)
            end = min(n, start + budget)
        omitted_prefix = omitted_prefix_base + start
        omitted_suffix = max(0, n - end)
        new_slots = (1 if omitted_prefix > 0 else 0) + (1 if omitted_suffix > 0 else 0)
        new_slots = min(limit - 1, max(0, new_slots))
        if new_slots == slots:
            break
        slots = new_slots
    omitted_prefix = omitted_prefix_base + start
    omitted_suffix = max(0, n - end)
    out: list[dict] = []
    if omitted_prefix > 0:
        out.append(_skip_row(f"⋮ ... ({omitted_prefix} rows omitted)"))
    out.extend(arr[start:end])
    if omitted_suffix > 0:
        out.append(_skip_row(f"⋮ ... ({omitted_suffix} rows omitted)"))
    truncated = omitted_prefix > 0 or omitted_suffix > 0
    if len(out) > limit:
        out = out[:limit]
        truncated = True
    return out, truncated


def make_numbered_diff(old_text: str, new_text: str, max_lines: int = 320) -> list[dict]:
    old_lines = old_text.splitlines()
    new_lines = new_text.splitlines()
    sm = difflib.SequenceMatcher(a=old_lines, b=new_lines)
    entries: list[dict] = []
    max_lines = max(16, int(max_lines or 320))
    # Keep bounded memory on huge files while preserving latest/hot rows.
    buffer_cap = max(max_lines + 256, min(6_000, max_lines * 6))
    dropped_head = 0

    def _push(row: dict):
        nonlocal dropped_head
        entries.append(row)
        if len(entries) <= buffer_cap:
            return
        drop = len(entries) - buffer_cap
        del entries[:drop]
        dropped_head += drop

    for tag, i1, i2, j1, j2 in sm.get_opcodes():
        if tag == "equal":
            for off in range(i2 - i1):
                _push(
                    {
                        "kind": "context",
                        "sign": " ",
                        "old_line": i1 + off + 1,
                        "new_line": j1 + off + 1,
                        "old_col": 1,
                        "new_col": 1,
                        "text": old_lines[i1 + off],
                    }
                )
        elif tag == "delete":
            for idx in range(i1, i2):
                _push(
                    {
                        "kind": "delete",
                        "sign": "-",
                        "old_line": idx + 1,
                        "new_line": None,
                        "old_col": 1,
                        "new_col": None,
                        "text": old_lines[idx],
                    }
                )
        elif tag == "insert":
            for idx in range(j1, j2):
                _push(
                    {
                        "kind": "add",
                        "sign": "+",
                        "old_line": None,
                        "new_line": idx + 1,
                        "old_col": None,
                        "new_col": 1,
                        "text": new_lines[idx],
                    }
                )
        elif tag == "replace":
            for idx in range(i1, i2):
                _push(
                    {
                        "kind": "delete",
                        "sign": "-",
                        "old_line": idx + 1,
                        "new_line": None,
                        "old_col": 1,
                        "new_col": None,
                        "text": old_lines[idx],
                    }
                )
            for idx in range(j1, j2):
                _push(
                    {
                        "kind": "add",
                        "sign": "+",
                        "old_line": None,
                        "new_line": idx + 1,
                        "old_col": None,
                        "new_col": 1,
                        "text": new_lines[idx],
                    }
                )
    out, _ = _compress_rows_keep_hotspot(entries, max_lines, prefix_omitted=dropped_head)
    return out

def render_numbered_diff_text(entries: list[dict]) -> str:
    out = []
    for row in entries:
        if row.get("kind") == "skip":
            out.append(f"    {str(row.get('text') or '⋮').strip()}")
            continue
        old_ln = row.get("old_line")
        new_ln = row.get("new_line")
        ln = old_ln if old_ln is not None else new_ln
        sign = row.get("sign", " ")
        text = row.get("text", "")
        out.append(f"{str(ln or ''):>6} {sign} {text}")
    return "\n".join(out)


def normalize_rel_preview_path(path_text: str) -> str:
    raw = str(path_text or "").strip().replace("\\", "/")
    if not raw:
        return ""
    try:
        p = PurePosixPath(raw)
        parts = [seg for seg in p.parts if seg not in ("", ".")]
        if not parts:
            return ""
        return PurePosixPath(*parts).as_posix()
    except Exception:
        return raw.lstrip("/")


def is_code_preview_candidate(path_text: str) -> bool:
    rel = normalize_rel_preview_path(path_text).lower()
    if not rel:
        return False
    name = PurePosixPath(rel).name.lower()
    ext = PurePosixPath(rel).suffix.lower()
    if ext in CODE_PREVIEW_EXTS:
        return True
    return name in CODE_PREVIEW_FILENAMES


def preview_kind_for_path(path_text: str) -> str:
    rel = normalize_rel_preview_path(path_text).lower()
    if not rel:
        return ""
    if rel.endswith((".html", ".htm")):
        return "html"
    if rel.endswith((".md", ".markdown")):
        return "markdown"
    if is_code_preview_candidate(rel):
        return "code"
    return ""


def build_code_preview_rows(
    before_text: str,
    after_text: str,
    *,
    max_rows: int = CODE_PREVIEW_STAGE_MAX_ROWS,
) -> tuple[list[dict], bool]:
    old_lines = str(before_text or "").replace("\r\n", "\n").replace("\r", "\n").split("\n")
    new_lines = str(after_text or "").replace("\r\n", "\n").replace("\r", "\n").split("\n")
    if old_lines == [""]:
        old_lines = []
    if new_lines == [""]:
        new_lines = []
    sm = difflib.SequenceMatcher(a=old_lines, b=new_lines, autojunk=False)
    max_rows = max(64, int(max_rows or CODE_PREVIEW_STAGE_MAX_ROWS))
    rows: list[dict] = []
    dropped_head = 0
    has_changes = False
    opcodes = list(sm.get_opcodes())
    for tag, *_ in opcodes:
        if tag != "equal":
            has_changes = True
            break
    # Avoid unbounded memory for giant files while keeping recent/hot rows.
    buffer_cap = max(max_rows + 2048, min(120_000, max_rows * 3))
    context_window = 96

    def _append(row: dict):
        nonlocal dropped_head
        rows.append(row)
        if len(rows) <= buffer_cap:
            return
        drop = len(rows) - buffer_cap
        del rows[:drop]
        dropped_head += drop

    def _append_skip(omitted_lines: int):
        n = max(0, int(omitted_lines or 0))
        if n <= 0:
            return
        _append(_skip_row(f"⋮ ... ({n} unchanged lines omitted)"))

    if not has_changes:
        total = len(new_lines)
        show = min(total, max_rows)
        for i in range(show):
            rows.append(
                {
                    "kind": "context",
                    "sign": " ",
                    "old_line": i + 1,
                    "new_line": i + 1,
                    "text": new_lines[i],
                }
            )
        truncated = total > show
        if truncated:
            rows.append(_skip_row(f"⋮ ... ({total - show} lines omitted)"))
        return rows, truncated

    for idx, (tag, i1, i2, j1, j2) in enumerate(opcodes):
        if tag == "equal":
            span = i2 - i1
            if span <= 0:
                continue
            prev_changed = idx > 0 and opcodes[idx - 1][0] != "equal"
            next_changed = idx + 1 < len(opcodes) and opcodes[idx + 1][0] != "equal"
            if prev_changed and next_changed:
                keep_head = min(context_window, span)
                keep_tail = min(context_window, max(0, span - keep_head))
                for off in range(keep_head):
                    _append(
                        {
                            "kind": "context",
                            "sign": " ",
                            "old_line": i1 + off + 1,
                            "new_line": j1 + off + 1,
                            "text": new_lines[j1 + off],
                        }
                    )
                _append_skip(span - keep_head - keep_tail)
                for off in range(keep_tail):
                    old_idx = i2 - keep_tail + off
                    new_idx = j2 - keep_tail + off
                    _append(
                        {
                            "kind": "context",
                            "sign": " ",
                            "old_line": old_idx + 1,
                            "new_line": new_idx + 1,
                            "text": new_lines[new_idx],
                        }
                    )
                continue
            if next_changed:
                keep_tail = min(context_window, span)
                _append_skip(span - keep_tail)
                for off in range(keep_tail):
                    old_idx = i2 - keep_tail + off
                    new_idx = j2 - keep_tail + off
                    _append(
                        {
                            "kind": "context",
                            "sign": " ",
                            "old_line": old_idx + 1,
                            "new_line": new_idx + 1,
                            "text": new_lines[new_idx],
                        }
                    )
                continue
            if prev_changed:
                keep_head = min(context_window, span)
                for off in range(keep_head):
                    _append(
                        {
                            "kind": "context",
                            "sign": " ",
                            "old_line": i1 + off + 1,
                            "new_line": j1 + off + 1,
                            "text": new_lines[j1 + off],
                        }
                    )
                _append_skip(span - keep_head)
                continue
            keep = min(context_window * 2, span)
            for off in range(keep):
                _append(
                    {
                        "kind": "context",
                        "sign": " ",
                        "old_line": i1 + off + 1,
                        "new_line": j1 + off + 1,
                        "text": new_lines[j1 + off],
                    }
                )
            _append_skip(span - keep)
            continue
        if tag == "delete":
            for i in range(i1, i2):
                _append(
                    {
                        "kind": "delete",
                        "sign": "-",
                        "old_line": i + 1,
                        "new_line": None,
                        "text": old_lines[i],
                    }
                )
            continue
        if tag == "insert":
            for j in range(j1, j2):
                _append(
                    {
                        "kind": "add",
                        "sign": "+",
                        "old_line": None,
                        "new_line": j + 1,
                        "text": new_lines[j],
                    }
                )
            continue
        if tag == "replace":
            for i in range(i1, i2):
                _append(
                    {
                        "kind": "delete",
                        "sign": "-",
                        "old_line": i + 1,
                        "new_line": None,
                        "text": old_lines[i],
                    }
                )
            for j in range(j1, j2):
                _append(
                    {
                        "kind": "add",
                        "sign": "+",
                        "old_line": None,
                        "new_line": j + 1,
                        "text": new_lines[j],
                    }
                )
    out, truncated = _compress_rows_keep_hotspot(rows, max_rows, prefix_omitted=dropped_head)
    if truncated and out and str(out[-1].get("kind", "")).lower() == "skip":
        out[-1]["text"] = str(out[-1].get("text") or "").strip() or f"⋮ ... preview truncated at {max_rows} rows"
    return out, truncated

class EventHub:
    def __init__(self):
        self._subs: list[queue.Queue] = []
        self._lock = threading.Lock()

    def subscribe(self) -> queue.Queue:
        q: queue.Queue = queue.Queue()
        with self._lock:
            self._subs.append(q)
        return q

    def unsubscribe(self, q: queue.Queue):
        with self._lock:
            self._subs = [x for x in self._subs if x is not q]

    def publish(self, event: dict):
        with self._lock:
            subs = list(self._subs)
        for q in subs:
            try:
                q.put_nowait(event)
            except queue.Full:
                pass

class TodoManager:
    def __init__(self):
        self.items: list[dict] = []
        self.lock = threading.Lock()

    def update(self, items: list[dict]) -> str:
        if not isinstance(items, list):
            raise ValueError("items must be array")
        validated = []
        in_progress_seen = False
        status_alias = {
            "todo": "pending",
            "doing": "in_progress",
            "inprogress": "in_progress",
            "in-progress": "in_progress",
            "done": "completed",
            "finish": "completed",
            "finished": "completed",
        }
        for idx, item in enumerate(items):
            if isinstance(item, str):
                raw = {"content": item, "status": "pending"}
            elif isinstance(item, dict):
                raw = item
            else:
                raise ValueError(f"item {idx}: invalid type")
            raw_content = str(raw.get("content", raw.get("text", raw.get("title", "")))).strip()
            content = normalize_work_text(raw_content)
            if not content:
                content = raw_content
            if not content:
                raise ValueError(f"item {idx}: content required")
            raw_status = str(raw.get("status", raw.get("state", "pending"))).strip().lower()
            status = status_alias.get(raw_status, raw_status or "pending")
            if status not in {"pending", "in_progress", "completed"}:
                status = "pending"
            content = normalize_work_text(content, status) or content
            active_form = str(
                raw.get(
                    "activeForm",
                    raw.get("active_form", raw.get("action", raw.get("current", ""))),
                )
            ).strip()
            owner = str(raw.get("owner", "") or "").strip().lower()
            if owner not in {"manager", "explorer", "developer", "reviewer"}:
                owner = ""
            key = trim(str(raw.get("key", "") or "").strip(), 120)
            if status == "in_progress":
                if in_progress_seen:
                    status = "pending"
                else:
                    in_progress_seen = True
            if not active_form:
                if status == "in_progress":
                    active_form = f"Working on: {content}"
                elif status == "completed":
                    active_form = f"Completed: {content}"
                else:
                    active_form = f"Pending: {content}"
            row = {"content": content, "status": status, "activeForm": active_form}
            if owner:
                row["owner"] = owner
            if key:
                row["key"] = key
            validated.append(row)
        if len(validated) > 20:
            raise ValueError("max 20 todos")
        if validated and not any(x["status"] == "in_progress" for x in validated):
            for row in validated:
                if row["status"] == "pending":
                    row["status"] = "in_progress"
                    row["activeForm"] = row.get("activeForm") or f"Working on: {row['content']}"
                    break
        with self.lock:
            if self.items == validated:
                return "No todo changes."
            self.items = validated
        return self.render()

    def has_open_items(self) -> bool:
        with self.lock:
            return any(x.get("status") != "completed" for x in self.items)

    def render(self) -> str:
        with self.lock:
            items = list(self.items)
        if not items:
            return "No todos."
        lines = []
        for item in items:
            marker = {"completed": "[x]", "in_progress": "[>]", "pending": "[ ]"}.get(
                item["status"], "[?]"
            )
            suffix = (
                f" <- {item['activeForm']}" if item["status"] == "in_progress" else ""
            )
            lines.append(f"{marker} {item['content']}{suffix}")
        done = sum(1 for x in items if x["status"] == "completed")
        lines.append(f"\n({done}/{len(items)} completed)")
        return "\n".join(lines)

    def snapshot(self) -> list[dict]:
        with self.lock:
            return [dict(x) for x in self.items]

    def complete_active(self, summary: str = "") -> dict:
        note = trim(str(summary or "").strip(), 180)
        with self.lock:
            rows = [dict(x) for x in self.items]
            if not rows:
                return {"updated": 0, "total": 0, "open_before": 0}
            open_before = sum(1 for x in rows if str(x.get("status", "pending")) != "completed")
            in_progress_indexes = [
                idx for idx, row in enumerate(rows) if str(row.get("status", "pending")) == "in_progress"
            ]
            changed = 0
            if in_progress_indexes:
                for idx in in_progress_indexes:
                    rows[idx]["status"] = "completed"
                    base = normalize_work_text(str(rows[idx].get("content", "")).strip()) or str(
                        rows[idx].get("content", "")
                    ).strip()
                    suffix = f" ({note})" if note else ""
                    rows[idx]["activeForm"] = f"Completed: {base}{suffix}".strip()
                    changed += 1
            else:
                for idx, row in enumerate(rows):
                    if str(row.get("status", "pending")) == "pending":
                        rows[idx]["status"] = "completed"
                        base = normalize_work_text(str(rows[idx].get("content", "")).strip()) or str(
                            rows[idx].get("content", "")
                        ).strip()
                        suffix = f" ({note})" if note else ""
                        rows[idx]["activeForm"] = f"Completed: {base}{suffix}".strip()
                        changed = 1
                        break
            if changed > 0:
                self.items = rows
            return {"updated": int(changed), "total": len(rows), "open_before": int(open_before)}

    def complete_all_open(self, summary: str = "") -> dict:
        note = trim(str(summary or "").strip(), 180)
        with self.lock:
            rows = [dict(x) for x in self.items]
            if not rows:
                return {"updated": 0, "total": 0, "open_before": 0}
            open_before = sum(1 for x in rows if str(x.get("status", "pending")) != "completed")
            changed = 0
            for idx, row in enumerate(rows):
                status = str(row.get("status", "pending"))
                if status == "completed":
                    continue
                rows[idx]["status"] = "completed"
                base = normalize_work_text(str(rows[idx].get("content", "")).strip()) or str(
                    rows[idx].get("content", "")
                ).strip()
                suffix = f" ({note})" if note else ""
                rows[idx]["activeForm"] = f"Completed: {base}{suffix}".strip()
                changed += 1
            if changed > 0:
                self.items = rows
            return {"updated": int(changed), "total": len(rows), "open_before": int(open_before)}

    def clear_all(self) -> dict:
        with self.lock:
            total = len(self.items)
            open_count = sum(1 for x in self.items if str(x.get("status", "pending")) != "completed")
            self.items = []
        return {"removed": int(total), "open_removed": int(open_count)}

